#!/bin/bash
# Inject pre-generated privacy strategies into calendar tasks.
#
# Usage:
#     bash experiments/3-5-strategy-selection-pipeline/generate_data.sh
#
# Prerequisites:
#     Strategy files must exist in strategies/privacy/strategy_*.yaml
#     (generated by generate_strategies.py — see Experiment.md)

set -euo pipefail

EXPERIMENT_DIR="$(cd "$(dirname "$0")" && pwd)"
MODEL="gemini-3.1-pro-preview"
INPUT="data/calendar-scheduling/final/small.yaml"

cd "$(git rev-parse --show-toplevel)"

STRATEGIES_DIR="$EXPERIMENT_DIR/strategies/privacy"
DATA_DIR="$EXPERIMENT_DIR/data/privacy"

if [ ! -d "$STRATEGIES_DIR" ]; then
    echo "ERROR: Strategies directory not found: $STRATEGIES_DIR"
    echo "Run generate_strategies.py first."
    exit 1
fi

N=$(ls -1 "$STRATEGIES_DIR"/strategy_*.yaml 2>/dev/null | wc -l | tr -d ' ')
if [ "$N" -eq 0 ]; then
    echo "ERROR: No strategy files found in $STRATEGIES_DIR"
    exit 1
fi

mkdir -p "$DATA_DIR"

echo "=== Privacy: Applying $N pre-generated strategies ==="
echo "Strategies directory: $STRATEGIES_DIR"
echo "Output directory: $DATA_DIR"
echo ""

for i in $(seq 0 $((N-1))); do
    OUTPUT_FILE="$DATA_DIR/strategy_$i.yaml"
    STRATEGY_FILE="$STRATEGIES_DIR/strategy_$i.yaml"

    if [ -f "$OUTPUT_FILE" ]; then
        echo "[privacy $i/$((N-1))] Skipping strategy_$i (already exists)"
        continue
    fi

    if [ ! -f "$STRATEGY_FILE" ]; then
        echo "[privacy $i/$((N-1))] ERROR: Strategy file not found: $STRATEGY_FILE"
        continue
    fi

    echo "[privacy $i/$((N-1))] Applying strategy_$i..."

    uv run --package sage-data-gen python -m sage_data_gen.calendar_scheduling.malicious.whimsical.privacy \
        "$INPUT" \
        -m "$MODEL" \
        --strategy-assignment single \
        --strategies-file "$STRATEGY_FILE" \
        -o "$OUTPUT_FILE"
done

echo ""
echo "Done! Generated data files:"
ls -la "$DATA_DIR/"
